setZoomLevel: (z) => {
  set({ zoomLevel: z })
  const s = get()
  saveSettings({ hapticsEnabled: s.hapticsEnabled, audioEnabled: s.audioEnabled,
    onboardingDone: s.onboardingDone, hasSeenFirstBoss: s.hasSeenFirstBoss,
    zoomLevel: z, hasSeenGhostEchoHint: s.hasSeenGhostEchoHint })
},

loadFromDisk: async () => {
  const data = await loadSettings()
  if (data) {
    set({
      hapticsEnabled:       data.hapticsEnabled,
      audioEnabled:         data.audioEnabled,
      onboardingDone:       data.onboardingDone       ?? false,
      hasSeenFirstBoss:     data.hasSeenFirstBoss     ?? false,
      zoomLevel:            data.zoomLevel             ?? 1,
      hasSeenGhostEchoHint: data.hasSeenGhostEchoHint ?? false,
    })
  }
  set({ loaded: true })
},

const savedZoom = useSettingsStore(s => s.zoomLevel)
const persistZoom = useSettingsStore(s => s.setZoomLevel)
const [zoom, setZoom] = useState<ZoomLevel>(savedZoom)

function zoomIn()  { const z = Math.min(2, zoom + 1) as ZoomLevel; setZoom(z); persistZoom(z) }
function zoomOut() { const z = Math.max(0, zoom - 1) as ZoomLevel; setZoom(z); persistZoom(z) }
